const checkpoints = [];
const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const cart = carts[0] || null;
// Compute next week's date range (Monday to following Monday) based on baseline 2026-03-03
const baseline = new Date('2026-03-03');
const day = baseline.getDay(); // 0=Sun
let daysToNextMonday = (8 - day) % 7;
if (daysToNextMonday === 0) daysToNextMonday = 7;
const nextWeekStart = new Date(baseline);
nextWeekStart.setDate(baseline.getDate() + daysToNextMonday);
const nextWeekEnd = new Date(nextWeekStart);
nextWeekEnd.setDate(nextWeekStart.getDate() + 7);
function isDateInNextWeek(dateStr) {
  if (!dateStr) return false;
  const d = new Date(dateStr);
  if (isNaN(d)) return false;
  return d >= nextWeekStart && d < nextWeekEnd;
}
// Qualifying products: electric chain hoists, electric power, capacity >= 2t
const qualifyingProducts = products.filter(p => p && p.categoryId === 'electric_chain_hoists' && p.hoistType === 'electric_chain_hoist' && p.powerSource === 'electric' && typeof p.capacityTonnes === 'number' && p.capacityTonnes >= 2);
let cheapestProduct = null;
qualifyingProducts.forEach(p => {
  if (!cheapestProduct || (p.dailyRate || 0) < (cheapestProduct.dailyRate || 0)) {
    cheapestProduct = p;
  }
});
const qualifyingCartItems = (cart ? cartItems.filter(ci => {
  if (ci.cartId !== cart.id) return false;
  const prod = products.find(p => p.id === ci.productId);
  if (!prod) return false;
  const capacityOk = prod.categoryId === 'electric_chain_hoists' && prod.hoistType === 'electric_chain_hoist' && prod.powerSource === 'electric' && typeof prod.capacityTonnes === 'number' && prod.capacityTonnes >= 2;
  const timingOk = isDateInNextWeek(ci.hireStartDate) && typeof ci.hireDurationDays === 'number' && ci.hireDurationDays === 3;
  const qtyOk = ci.quantity === 1;
  return capacityOk && timingOk && qtyOk;
}) : []);
const hasCheapestInCart = !!(cheapestProduct && qualifyingCartItems.some(ci => ci.productId === cheapestProduct.id));
// CP1 (0.4): At least one qualifying ≥2t electric hoist in cart for 3 days next week with quantity 1
checkpoints.push({ passed: qualifyingCartItems.length > 0, weight: 0.4 });
// CP2 (0.3): The qualifying cart item uses the cheapest qualifying product
checkpoints.push({ passed: hasCheapestInCart, weight: 0.3 });
// CP3 (0.3): Depot pickup selected on cart for this hire
const depotPickupSelected = !!(cart && cart.deliveryMethod === 'depot_pickup' && qualifyingCartItems.length > 0);
checkpoints.push({ passed: depotPickupSelected, weight: 0.3 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

