const day = baseline.getDay(); // 2 (Tue)
const deltaToSat = (6 - day + 7) % 7;
const upcomingSaturday = new Date(baseline);
upcomingSaturday.setDate(baseline.getDate() + deltaToSat);
function sameYMD(a, b) {
  return a.getFullYear() === b.getFullYear() && a.getMonth() === b.getMonth() && a.getDate() === b.getDate();
}
