const checkpoints = [];
const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const hireOrders = JSON.parse(localStorage.getItem('hire_orders') || '[]');
const cart = carts[0] || null;
// Two weeks from baseline 2026-03-03 -> 2026-03-17
const baseline = new Date('2026-03-03');
const expectedStart = new Date(baseline);
expectedStart.setDate(baseline.getDate() + 14);
function sameYMD(a, b) {
  return a.getFullYear() === b.getFullYear() && a.getMonth() === b.getMonth() && a.getDate() === b.getDate();
}
function ipRank(ip) {
  if (!ip) return null;
  const m = { ip54: 54, ip55: 55, ip65: 65, ip66: 66, ip67: 67 };
  return m[String(ip).toLowerCase()] != null ? m[String(ip).toLowerCase()] : null;
}
const minIpRank = ipRank('ip65');
// Qualifying products: outdoor or indoor_outdoor electric chain hoists with IP >= 65
const qualifyingProducts = products.filter(p => {
  if (!p) return false;
  if (p.categoryId !== 'electric_chain_hoists' || p.hoistType !== 'electric_chain_hoist') return false;
  if (!(p.environment === 'outdoor' || p.environment === 'indoor_outdoor')) return false;
  const r = ipRank(p.ipRating);
  return r != null && r >= minIpRank;
});
const qualifyingIds = qualifyingProducts.map(p => p.id);
const itemsForCart = cart ? cartItems.filter(ci => ci.cartId === cart.id) : [];
const qualifyingCartItems = itemsForCart.filter(ci => {
  const prod = products.find(p => p.id === ci.productId);
  if (!prod || !qualifyingIds.includes(prod.id)) return false;
  const start = new Date(ci.hireStartDate);
  if (isNaN(start)) return false;
  const startOk = sameYMD(start, expectedStart);
  const durationOk = typeof ci.hireDurationDays === 'number' && ci.hireDurationDays === 10;
  const qtyOk = ci.quantity === 1;
  return startOk && durationOk && qtyOk;
});
// CP1 (0.5): At least one qualifying outdoor-rated electric hoist IP65+ hired for 10 days starting two weeks from baseline
checkpoints.push({ passed: qualifyingCartItems.length > 0, weight: 0.5 });
// Checkout: site delivery to postcode 30301 with rooftop note
let order = null;
if (cart) {
  order = hireOrders.find(o => o.cartId === cart.id && o.deliveryMethod === 'site_delivery' && typeof o.deliveryNotes === 'string' && o.deliveryNotes.toLowerCase().includes('rooftop')) || null;
}
const postcodeMatches = !!(cart && cart.deliveryPostcode === '30301') || !!(order && order.addressPostcode === '30301');
const siteDeliveryOk = !!(cart && cart.deliveryMethod === 'site_delivery' && order && postcodeMatches);
// CP2 (0.5): Site delivery selected with postcode 30301 and a rooftop installation note recorded in the hire order
checkpoints.push({ passed: qualifyingCartItems.length > 0 && siteDeliveryOk, weight: 0.5 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
